import{_ as o,C as d,o as i,c as r,ai as l,E}from"./chunks/framework.BIXs0jTs.js";const t="/assets/preface-cover.Balx8Fq4.png",c=JSON.parse('{"title":"Claude Code 概览","description":"","frontmatter":{"title":"Claude Code 概览","outline":"deep"},"headers":[],"relativePath":"10-claude-code/intro.md","filePath":"10-claude-code/intro.md","lastUpdated":null}'),A={name:"10-claude-code/intro.md"};function n(C,e,u,B,s,p){const a=d("Mermaid");return i(),r("div",null,[e[0]||(e[0]=l('<h1 id="claude-code-概览" tabindex="-1">Claude Code 概览 <a class="header-anchor" href="#claude-code-概览" aria-label="Permalink to &quot;Claude Code 概览&quot;">​</a></h1><p><img src="'+t+'" alt="图 1‑0 夜晚办公室中一位开发者与屏幕上的对话窗口，象征人与 Claude Code 的协作"></p><blockquote><p><strong>Claude Code 不是“会写代码的聊天机器人”，而是一个可以在你的项目里持续执行任务的工程代理（Agent）。</strong></p></blockquote><p>在深入 Skill 和 MCP 之前，我们需要先回答一个基础问题：<strong>Claude Code 到底是什么，它和你熟悉的那些“聊天式 AI”有什么不一样？</strong><br> 本章会从三个角度来介绍 Claude Code：</p><ul><li>它在整个开发流程中的<strong>定位</strong>；</li><li>它提供的几种核心<strong>模式（Ask / Plan / Agent / Debug 等）</strong>；</li><li>它在日常工作中最常见的<strong>使用场景与工作流</strong>。</li></ul><p>你可以把这一章看作是后续所有内容的“地图”。等你读完之后，再回头看 Skill 和 MCP，会更容易知道：<strong>我到底在给谁“装能力”、加接口。</strong></p><h2 id="_1-1-claude-code-是什么" tabindex="-1">1.1 Claude Code 是什么？ <a class="header-anchor" href="#_1-1-claude-code-是什么" aria-label="Permalink to &quot;1.1 Claude Code 是什么？&quot;">​</a></h2><p>如果只用一句话来描述：</p><blockquote><p><strong>Claude Code 是运行在你工程环境中的 AI 工程助手，它可以读取代码、修改文件、执行命令，并在多轮对话中持续推进一个具体任务。</strong></p></blockquote><p>和普通的云端聊天模型相比，Claude Code 有几个显著特点：</p><ul><li><p><strong>它“住”在你的项目里</strong>：<br> 它可以直接访问你的代码文件、测试脚本、配置和日志，而不是只看你复制粘贴的一小段文本。</p></li><li><p><strong>它能够“动手”而不仅是“动嘴”</strong>：<br> 它不仅能给出建议，还能在经过你授权后，直接对文件进行修改、运行测试命令、收集输出并继续分析。</p></li><li><p><strong>它支持多轮、长链路任务</strong>：<br> 例如：“找出导致这个接口超时的原因 → 修改代码 → 跑测试 → 根据测试结果再做一次调整”，整个过程可以在同一条“任务线程”中完成。</p></li></ul><p>从形象上看，你可以把 Claude Code 想象成这样（见下图）：</p>',12)),E(a,{id:"mermaid_382ee1e8",graph:"flowchart%20LR%0A%20%20dev%5B%22%E5%BC%80%E5%8F%91%E8%80%85%22%5D%20%3C--%3E%7C%E8%87%AA%E7%84%B6%E8%AF%AD%E8%A8%80%E7%9B%AE%E6%A0%87%20%2F%20%E5%8F%8D%E9%A6%88%7C%20claude%5B%22Claude%20Code%22%5D%0A%20%20claude%20%3C--%3E%7C%E8%AF%BB%E5%86%99%7C%20files%5B%22%E4%BB%A3%E7%A0%81%E4%B8%8E%E9%85%8D%E7%BD%AE%E6%96%87%E4%BB%B6%22%5D%0A%20%20claude%20%3C--%3E%7C%E6%89%A7%E8%A1%8C%E5%91%BD%E4%BB%A4%20%2F%20%E6%94%B6%E9%9B%86%E8%BE%93%E5%87%BA%7C%20shell%5B%22%E6%B5%8B%E8%AF%95%20%2F%20%E6%9E%84%E5%BB%BA%20%2F%20%E8%84%9A%E6%9C%AC%22%5D%0A%20%20claude%20--%3E%20reports%5B%22%E6%80%BB%E7%BB%93%20%2F%20%E6%96%87%E6%A1%A3%20%2F%20%E5%BB%BA%E8%AE%AE%22%5D"}),e[1]||(e[1]=l('<h2 id="_1-2-claude-code-与-普通聊天-ai-的关键区别" tabindex="-1">1.2 Claude Code 与“普通聊天 AI”的关键区别 <a class="header-anchor" href="#_1-2-claude-code-与-普通聊天-ai-的关键区别" aria-label="Permalink to &quot;1.2 Claude Code 与“普通聊天 AI”的关键区别&quot;">​</a></h2><p>很多第一次使用 Claude Code 的同学，会有这样一种感觉：</p><blockquote><p>“好像也是在聊天窗口打字，Claude 给我一些代码和建议，和普通的 Claude / ChatGPT 有什么本质不同？”</p></blockquote><p>为了回答这个问题，我们可以从下面几个维度来对比。</p><h3 id="_1-2-1-上下文来源-不仅是-你发来的那几段文字" tabindex="-1">1.2.1 上下文来源：不仅是“你发来的那几段文字” <a class="header-anchor" href="#_1-2-1-上下文来源-不仅是-你发来的那几段文字" aria-label="Permalink to &quot;1.2.1 上下文来源：不仅是“你发来的那几段文字”&quot;">​</a></h3><ul><li><strong>普通聊天模型</strong>的上下文，大多来自你手动粘贴的内容：一两段代码、一个错误日志、一段需求描述。</li><li><strong>Claude Code</strong> 则可以直接： <ul><li>读取你项目中的多个文件；</li><li>基于文件系统结构理解模块关系；</li><li>在需要时主动查找相关代码，而不是只在你贴给它的那几行里“瞎猜”。</li></ul></li></ul><p>换句话说，它看到的是<strong>整个工程</strong>，而不是一个个被剪切下来的小片段。</p><h3 id="_1-2-2-行动能力-从-给建议-到-执行操作" tabindex="-1">1.2.2 行动能力：从“给建议”到“执行操作” <a class="header-anchor" href="#_1-2-2-行动能力-从-给建议-到-执行操作" aria-label="Permalink to &quot;1.2.2 行动能力：从“给建议”到“执行操作”&quot;">​</a></h3><p>普通聊天模型给出的“修改建议”，通常需要你手动复制粘贴到编辑器中，再自己调整和保存；<br> Claude Code 则可以在你的确认下，直接：</p><ul><li>修改一个或多个文件，并给出 diff；</li><li>运行测试命令或脚本（例如 <code>npm test</code>、<code>pytest</code>、<code>go test</code>）；</li><li>根据命令输出继续分析问题、调整方案。</li></ul><p>这意味着，你可以让 Claude Code 负责更多“机械且耗时”的环节，把注意力集中在<strong>决策和审查</strong>上。</p><h3 id="_1-2-3-任务思维-从-一问一答-到-完整工作流" tabindex="-1">1.2.3 任务思维：从“一问一答”到“完整工作流” <a class="header-anchor" href="#_1-2-3-任务思维-从-一问一答-到-完整工作流" aria-label="Permalink to &quot;1.2.3 任务思维：从“一问一答”到“完整工作流”&quot;">​</a></h3><p>普通聊天往往是“你问一句，它答一句”，每次问题都相对独立；<br> 而 Claude Code 被设计成可以执行<strong>完整工作流</strong>的代理：</p><ul><li>先读代码理解现状；</li><li>再提出多种可行方案，并权衡利弊；</li><li>然后按选定方案逐步修改、运行验证；</li><li>最后整理输出 changelog、文档或总结报告。</li></ul><p>这种“任务导向”的思维方式，是后面 Skill 和 MCP 能够发挥威力的前提。</p><h2 id="_1-3-claude-code-的核心模式-ask、plan、agent、debug" tabindex="-1">1.3 Claude Code 的核心模式：Ask、Plan、Agent、Debug…… <a class="header-anchor" href="#_1-3-claude-code-的核心模式-ask、plan、agent、debug" aria-label="Permalink to &quot;1.3 Claude Code 的核心模式：Ask、Plan、Agent、Debug……&quot;">​</a></h2><p>为了更好地支持不同类型的任务，Claude Code 通常会提供多种“模式”（具体名称可能随版本略有变化，本书统一采用以下称呼）：</p><ul><li><strong>Ask 模式</strong>：只读分析，不做修改；</li><li><strong>Plan 模式</strong>：先问清楚，再给方案；</li><li><strong>Agent 模式</strong>：可以读写文件、执行命令，推进复杂任务；</li><li><strong>Debug/Repair 模式</strong>：围绕错误和失败测试进行快速定位与修复。</li></ul><p>你可以根据当前任务的性质，选用合适的模式。</p>',19)),E(a,{id:"mermaid_64a5695c",graph:"flowchart%20LR%0A%20%20Ask%5BAsk%20%E6%A8%A1%E5%BC%8F%3Cbr%2F%3E%E5%8F%AA%E8%AF%BB%E5%88%86%E6%9E%90%5D%20--%3E%7C%E7%90%86%E8%A7%A3%E4%BB%A3%E7%A0%81%20%2F%20%E8%A7%A3%E9%87%8A%7C%20Dev%0A%20%20Plan%5BPlan%20%E6%A8%A1%E5%BC%8F%3Cbr%2F%3E%E6%96%B9%E6%A1%88%E8%AE%BE%E8%AE%A1%5D%20--%3E%7C%E5%88%97%E5%87%BA%E9%80%89%E9%A1%B9%20%2F%20%E8%AF%84%E4%BC%B0%E9%A3%8E%E9%99%A9%7C%20Dev%0A%20%20Agent%5BAgent%20%E6%A8%A1%E5%BC%8F%3Cbr%2F%3E%E6%89%A7%E8%A1%8C%E6%94%B9%E5%8A%A8%5D%20--%3E%7C%E6%94%B9%E4%BB%A3%E7%A0%81%20%2F%20%E8%B7%91%E6%B5%8B%E8%AF%95%7C%20Repo%0A%20%20Debug%5BDebug%20%2F%20Repair%3Cbr%2F%3E%E9%97%AE%E9%A2%98%E5%AE%9A%E4%BD%8D%5D%20--%3E%7C%E9%94%99%E8%AF%AF%E5%88%86%E6%9E%90%20%2F%20Patch%20%E5%BB%BA%E8%AE%AE%7C%20Repo%0A%0A%20%20Dev((%E5%BC%80%E5%8F%91%E8%80%85))%20--%3E%20Ask%0A%20%20Dev%20--%3E%20Plan%0A%20%20Dev%20--%3E%20Agent%0A%20%20Dev%20--%3E%20Debug%0A%20%20Repo%5B(%E4%BB%A3%E7%A0%81%E5%BA%93%20%2F%20%E7%8E%AF%E5%A2%83)%5D%20--%3E%20Debug"}),e[2]||(e[2]=l('<h3 id="_1-3-1-ask-安全的-阅读与解说-模式" tabindex="-1">1.3.1 Ask：安全的“阅读与解说”模式 <a class="header-anchor" href="#_1-3-1-ask-安全的-阅读与解说-模式" aria-label="Permalink to &quot;1.3.1 Ask：安全的“阅读与解说”模式&quot;">​</a></h3><p>在 Ask 模式下，Claude Code 的职责是<strong>理解和解释</strong>，而不是修改。</p><p>常见用法包括：</p><ul><li>让它帮你解释一段复杂的业务逻辑；</li><li>让它梳理某个模块的职责和依赖关系；</li><li>让它根据现有代码写出“新人入门指南”或简要文档。</li></ul><p>因为不会改动任何文件，这个模式非常适合作为“安全的第一步”——尤其是在一个你还不熟悉的项目里。</p><h3 id="_1-3-2-plan-先问清需求-再动手" tabindex="-1">1.3.2 Plan：先问清需求，再动手 <a class="header-anchor" href="#_1-3-2-plan-先问清需求-再动手" aria-label="Permalink to &quot;1.3.2 Plan：先问清需求，再动手&quot;">​</a></h3><p>Plan 模式的目标，是在真正改代码之前，先把：</p><ul><li>任务目标；</li><li>可选方案；</li><li>潜在风险；</li><li>预计影响范围；</li></ul><p>这些内容<strong>讨论清楚</strong>。</p><p>例如，当你打算做一次重构时，可以用 Plan 模式让 Claude Code 先给出：</p><ul><li>当前实现的优缺点；</li><li>若干可行的重构方案；</li><li>每种方案的工作量评估和风险点；</li><li>推荐方案及其实施步骤。</li></ul><p>等你对方案满意之后，再切换到 Agent 模式执行真正的修改。</p><h3 id="_1-3-3-agent-真正-干活-的模式" tabindex="-1">1.3.3 Agent：真正“干活”的模式 <a class="header-anchor" href="#_1-3-3-agent-真正-干活-的模式" aria-label="Permalink to &quot;1.3.3 Agent：真正“干活”的模式&quot;">​</a></h3><p>Agent 模式是 Claude Code 的“工作马”。在这个模式下，它可以：</p><ul><li>读取和修改多个文件；</li><li>执行测试、构建或自定义脚本；</li><li>根据命令输出不断调整自己的操作。</li></ul><p>典型任务包括：</p><ul><li>为某个模块补齐单元测试并确保全部通过；</li><li>对某段逻辑进行重构，并更新所有受影响的调用方；</li><li>根据错误日志执行一轮“定位 → 修复 → 回归测试”的完整流程。</li></ul><p>后面我们会通过多个实战章节，展示如何安全地让 Agent 模式接管这些任务。</p><h3 id="_1-3-4-debug-repair-面向错误的快速响应" tabindex="-1">1.3.4 Debug / Repair：面向错误的快速响应 <a class="header-anchor" href="#_1-3-4-debug-repair-面向错误的快速响应" aria-label="Permalink to &quot;1.3.4 Debug / Repair：面向错误的快速响应&quot;">​</a></h3><p>当你遇到错误堆栈、失败测试或线上告警时，可以切换到 Debug/Repair 相关模式，让 Claude Code 帮你：</p><ul><li>解析错误日志，归类错误类型；</li><li>提出可能的原因假设和排查步骤；</li><li>生成最小修改集（patch），并指导你如何验证修复效果。</li></ul><p>在结合 MCP 接入日志系统和监控平台之后，这一类模式会更加强大——它可以直接从外部系统读取数据，而不再需要你手动复制粘贴。</p><h2 id="_1-4-一个典型的-claude-code-工作流长什么样" tabindex="-1">1.4 一个典型的 Claude Code 工作流长什么样？ <a class="header-anchor" href="#_1-4-一个典型的-claude-code-工作流长什么样" aria-label="Permalink to &quot;1.4 一个典型的 Claude Code 工作流长什么样？&quot;">​</a></h2><p>为了更直观地理解 Claude Code 在日常开发中的角色，我们来看一个简化的工作流示意（见下方流程图）：</p><ol><li><p><strong>确认目标（人）</strong><br> 你通过自然语言描述想完成的事情，例如：“把这个接口的平均响应时间从 800ms 降到 300ms 左右”。</p></li><li><p><strong>分析现状（Claude Code / Ask + Plan）</strong><br> Claude Code 阅读相关代码和配置，分析当前实现，列出可能的性能瓶颈，并给出若干优化方案。</p></li><li><p><strong>选择方案（人）</strong><br> 你根据业务理解和风险评估，选择其中一到两个方案，并补充必要的约束条件。</p></li><li><p><strong>实施与验证（Claude Code / Agent）</strong><br> Claude Code 按方案修改代码、运行测试或基准脚本，并根据结果进行微调。</p></li><li><p><strong>总结与交付（Claude Code + 人）</strong><br> Claude Code 帮你整理这次优化的变更点、风险提示和测试结果；<br> 你在此基础上补充业务说明和后续计划，形成最终的 PR 描述或技术说明。</p></li></ol>',25)),E(a,{id:"mermaid_64a55a64",graph:"flowchart%20LR%0A%20%20A%5B%22%E5%AE%9A%E4%B9%89%E7%9B%AE%E6%A0%87%5Cn%E4%BE%8B%E5%A6%82%E9%99%8D%E4%BD%8E%E6%8E%A5%E5%8F%A3%E5%93%8D%E5%BA%94%E6%97%B6%E9%97%B4%22%5D%20--%3E%20B%5B%22Claude%20Code%20%E5%88%86%E6%9E%90%E7%8E%B0%E7%8A%B6%5CnAsk%20%2B%20Plan%22%5D%0A%20%20B%20--%3E%20C%5B%22%E4%BA%BA%E7%B1%BB%E9%80%89%E6%8B%A9%E6%96%B9%E6%A1%88%5Cn%E8%A1%A5%E5%85%85%E7%BA%A6%E6%9D%9F%22%5D%0A%20%20C%20--%3E%20D%5B%22Claude%20Code%20%E6%89%A7%E8%A1%8C%E6%94%B9%E5%8A%A8%5CnAgent%20%E6%A8%A1%E5%BC%8F%22%5D%0A%20%20D%20--%3E%20E%5B%22%E8%BF%90%E8%A1%8C%E6%B5%8B%E8%AF%95%20%2F%20%E5%9F%BA%E5%87%86%5Cn%E6%94%B6%E9%9B%86%E7%BB%93%E6%9E%9C%22%5D%0A%20%20E%20--%3E%20F%7B%22%E7%BB%93%E6%9E%9C%E8%BE%BE%E6%A0%87%EF%BC%9F%22%7D%0A%20%20F%20--%20%E5%90%A6%20--%3E%20B%0A%20%20F%20--%20%E6%98%AF%20--%3E%20G%5B%22Claude%20Code%20%E6%95%B4%E7%90%86%E6%80%BB%E7%BB%93%5Cn%E5%8F%98%E6%9B%B4%E7%82%B9%20%2F%20%E9%A3%8E%E9%99%A9%20%2F%20%E6%B5%8B%E8%AF%95%22%5D%0A%20%20G%20--%3E%20H%5B%22%E4%BA%BA%E7%B1%BB%E8%A1%A5%E5%85%85%E4%B8%9A%E5%8A%A1%E8%AF%B4%E6%98%8E%5Cn%E6%8F%90%E4%BA%A4%20PR%20%2F%20%E5%8F%98%E6%9B%B4%E5%8D%95%22%5D"}),e[3]||(e[3]=l('<p>在这个过程中，人和 Claude Code 的分工大致是：</p><ul><li>人：负责目标定义、方案选择、风险把控、最终决策；</li><li>Claude Code：负责信息收集、方案生成、具体改动和验证步骤的执行。</li></ul><h2 id="_1-5-小结-把-claude-code-放在正确的位置上" tabindex="-1">1.5 小结：把 Claude Code 放在正确的位置上 <a class="header-anchor" href="#_1-5-小结-把-claude-code-放在正确的位置上" aria-label="Permalink to &quot;1.5 小结：把 Claude Code 放在正确的位置上&quot;">​</a></h2><p>在这一章里，我们没有急着讨论具体命令和配置，而是重点回答了三个更基础的问题：</p><ul><li>Claude Code 是什么，它和普通聊天模型有什么不同；</li><li>它有哪些核心模式，每种模式适合做什么；</li><li>在一个简单但完整的工作流中，人和 Claude Code 应该如何分工。</li></ul><p>在后续章节中，我们会逐步缩小镜头，深入到更具体的场景中：<br> 先是如何用 Claude Code 读懂代码、重构和调试；<br> 然后是如何用 Skill 把这些能力固化下来；<br> 最后是如何用 MCP 把外部系统接入这个“工程大脑”。</p><p>在继续阅读之前，你可以先在自己的项目里思考一个问题：<br><strong>如果今天只能让 Claude Code 帮你做一件事，那会是什么？</strong><br> 带着这个问题进入下一章，你会更容易把书中的内容和自己的实际需求对应起来。</p>',7))])}const _=o(A,[["render",n]]);export{c as __pageData,_ as default};
